import React, { useState } from 'react';
import { registerDoctor } from '../services/auth';

export default function Dashboard(){
  const role = localStorage.getItem('role') || 'ADMIN';
  const [docForm, setDocForm] = useState({username: '', password: ''});
  const [msg, setMsg] = useState({text: '', type: ''});

  async function handleRegisterDoctor(e){
    e.preventDefault();
    setMsg({text: '', type: ''});
    try {
      await registerDoctor(docForm);
      setMsg({text: 'Doctor successfully registered!', type: 'success'});
      setDocForm({username: '', password: ''});
    } catch(err) {
      setMsg({text: err.response?.data || 'Failed to register doctor', type: 'error'});
    }
  }

  return (
    <div>
      <h2>Dashboard</h2>
      <p style={{fontSize: '1.2rem', marginBottom: '20px'}}>Welcome to the Hospital Management System! You are logged in as: <strong>{role}</strong></p>

      {role === 'ADMIN' && (
        <div style={{display: 'flex', gap: '30px', flexWrap: 'wrap', alignItems: 'flex-start'}}>
          <div style={{flex: '1', minWidth: '300px', background: 'rgba(255,255,255,0.5)', padding: '20px', borderRadius: '15px'}}>
            <h3>Admin Quick Links</h3>
            <ul style={{listStyle: 'none', padding: 0, lineHeight: '2'}}>
              <li><a href="/patients" style={{color: '#2a5298', fontWeight: 'bold', textDecoration: 'none'}}>➜ Manage Patients</a></li>
              <li><a href="/doctors" style={{color: '#2a5298', fontWeight: 'bold', textDecoration: 'none'}}>➜ Manage Doctors</a></li>
              <li><a href="/appointments" style={{color: '#2a5298', fontWeight: 'bold', textDecoration: 'none'}}>➜ Appointments</a></li>
              <li><a href="/billing" style={{color: '#2a5298', fontWeight: 'bold', textDecoration: 'none'}}>➜ Billing</a></li>
            </ul>
          </div>

          <div className="form" style={{flex: '1', minWidth: '300px', margin: '0', boxShadow: 'none', background: 'rgba(255,255,255,0.5)', border: '1px solid rgba(0,0,0,0.1)'}}>
            <h3>Register New Doctor</h3>
            {msg.text && <div className={`alert ${msg.type === 'success' ? 'success' : ''}`}>{msg.text}</div>}
            <form onSubmit={handleRegisterDoctor}>
              <input placeholder="Doctor Username" value={docForm.username} onChange={e=>setDocForm({...docForm,username:e.target.value})} required />
              <input type="password" placeholder="Password" value={docForm.password} onChange={e=>setDocForm({...docForm,password:e.target.value})} required />
              <button className="btn">Register Doctor</button>
            </form>
          </div>
        </div>
      )}

      {role === 'DOCTOR' && (
        <div>
          <p>Welcome, Doctor! View your appointments and manage patients from your dashboard.</p>
          <a href="/appointments" className="btn" style={{display: 'inline-block', textDecoration: 'none'}}>View Appointments</a>
        </div>
      )}

      {role === 'PATIENT' && (
        <div>
          <p>Welcome! You can book an appointment or check your billing history.</p>
          <div className="flex" style={{justifyContent: 'flex-start'}}>
            <a href="/appointments" className="btn" style={{textDecoration: 'none'}}>My Appointments</a>
            <a href="/billing" className="btn secondary" style={{textDecoration: 'none'}}>My Billing</a>
          </div>
        </div>
      )}
    </div>
  );
}
